codeExercises.solution:
import React, { useState } from 'react';
import axios from 'axios';

const FeedbackForm = ({ onFeedbackAdded }) => {
  const [username, setUsername] = useState('');
  const [comment, setComment] = useState('');
  const [rating, setRating] = useState(5);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('/api/feedback', { username, comment, rating });
      onFeedbackAdded(response.data); // Cập nhật UI với feedback mới
      setUsername('');
      setComment('');
      setRating(5);
    } catch (error) {
      console.error('Failed to submit feedback:', error);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input type="text" placeholder="Tên của bạn" value={username} onChange={(e) => setUsername(e.target.value)} required />
      <textarea placeholder="Cảm nghĩ của bạn" value={comment} onChange={(e) => setComment(e.target.value)} required />
      <select value={rating} onChange={(e) => setRating(Number(e.target.value))}>
        <option value={5}>5 sao</option>
        <option value={4}>4 sao</option>
        <option value={3}>3 sao</option>
        <option value={2}>2 sao</option>
        <option value={1}>1 sao</option>
      </select>
      <button type="submit">Gửi</button>
    </form>
  );
};

export default FeedbackForm;
